   956→func useDiffCache(noCache bool, manifestInfos []*apiclient.ManifestResponse, sources []v1alpha1.ApplicationSource, app *v1alpha1.Application, manifestRevisions []string, statusRefreshTimeout time.Duration, serverSideDiff bool, log *log.Entry) bool {
   957→	if noCache {
   958→		log.WithField("useDiffCache", "false").Debug("noCache is true")
   959→		return false
   960→	}
   961→	refreshType, refreshRequested := app.IsRefreshRequested()
   962→	if refreshRequested {
   963→		log.WithField("useDiffCache", "false").Debugf("refresh type %s requested", string(refreshType))
   964→		return false
   965→	}
   966→	// serverSideDiff should still use cache even if status is expired.
   967→	// This is an attempt to avoid hitting k8s API server too frequently during
   968→	// app refresh with serverSideDiff is enabled. If there are negative side
   969→	// effects identified with this approach, the serverSideDiff should be removed
   970→	// from this condition.
   971→	if app.Status.Expired(statusRefreshTimeout) && !serverSideDiff {
   972→		log.WithField("useDiffCache", "false").Debug("app.status.expired")
   973→		return false
   974→	}
   975→
   976→	if len(manifestInfos) != len(sources) {
   977→		log.WithField("useDiffCache", "false").Debug("manifestInfos len != sources len")
   978→		return false
   979→	}
   980→
   981→	revisionChanged := !reflect.DeepEqual(app.Status.GetRevisions(), manifestRevisions)
   982→	if revisionChanged {
   983→		log.WithField("useDiffCache", "false").Debug("revisionChanged")
   984→		return false
   985→	}
   986→
   987→	if !specEqualsCompareTo(app.Spec, app.Status.Sync.ComparedTo) {
   988→		log.WithField("useDiffCache", "false").Debug("specChanged")
   989→		return false
   990→	}
   991→
   992→	log.WithField("useDiffCache", "true").Debug("using diff cache")
   993→	return true
   994→}
