   996→// specEqualsCompareTo compares the application spec to the comparedTo status. It normalizes the destination to match
   997→// the comparedTo destination before comparing. It does not mutate the original spec or comparedTo.
   998→func specEqualsCompareTo(spec v1alpha1.ApplicationSpec, comparedTo v1alpha1.ComparedTo) bool {
   999→	// Make a copy to be sure we don't mutate the original.
  1000→	specCopy := spec.DeepCopy()
  1001→	currentSpec := specCopy.BuildComparedToStatus()
  1002→
  1003→	// The spec might have been augmented to include both server and name, so change it to match the comparedTo before
  1004→	// comparing.
  1005→	if comparedTo.Destination.Server == "" {
  1006→		currentSpec.Destination.Server = ""
  1007→	}
  1008→	if comparedTo.Destination.Name == "" {
  1009→		currentSpec.Destination.Name = ""
  1010→	}
  1011→
  1012→	// Set IsServerInferred to false on both, because that field is not important for comparison.
  1013→	comparedTo.Destination.SetIsServerInferred(false)
  1014→	currentSpec.Destination.SetIsServerInferred(false)
  1015→
  1016→	return reflect.DeepEqual(comparedTo, currentSpec)
  1017→}

