1882→// needRefreshAppStatus answers if application status needs to be refreshed.
  1883→// Returns true if application never been compared, has changed or comparison result has expired.
  1884→// Additionally, it returns whether full refresh was requested or not.
  1885→// If full refresh is requested then target and live state should be reconciled, else only live state tree should be updated.
  1886→func (ctrl *ApplicationController) needRefreshAppStatus(app *appv1.Application, statusRefreshTimeout, statusHardRefreshTimeout time.Duration) (bool, appv1.RefreshType, CompareWith) {
  1887→	logCtx := getAppLog(app)
  1888→	var reason string
  1889→	compareWith := CompareWithLatest
  1890→	refreshType := appv1.RefreshTypeNormal
  1891→
  1892→	softExpired := app.Status.ReconciledAt == nil || app.Status.ReconciledAt.Add(statusRefreshTimeout).Before(time.Now().UTC())
  1893→	hardExpired := (app.Status.ReconciledAt == nil || app.Status.ReconciledAt.Add(statusHardRefreshTimeout).Before(time.Now().UTC())) && statusHardRefreshTimeout.Seconds() != 0
  1894→
  1895→	if requestedType, ok := app.IsRefreshRequested(); ok {
  1896→		compareWith = CompareWithLatestForceResolve
  1897→		// user requested app refresh.
  1898→		refreshType = requestedType
  1899→		reason = fmt.Sprintf("%s refresh requested", refreshType)
  1900→	} else {
  1901→		if !currentSourceEqualsSyncedSource(app) {
  1902→			reason = "spec.source differs"
  1903→			compareWith = CompareWithLatestForceResolve
  1904→			if app.Spec.HasMultipleSources() {
  1905→				reason = "at least one of the spec.sources differs"
  1906→			}
  1907→		} else if hardExpired || softExpired {
  1908→			// The commented line below mysteriously crashes if app.Status.ReconciledAt is nil
  1909→			// reason = fmt.Sprintf("comparison expired. reconciledAt: %v, expiry: %v", app.Status.ReconciledAt, statusRefreshTimeout)
  1910→			// TODO: find existing Golang bug or create a new one
  1911→			reconciledAtStr := "never"
  1912→			if app.Status.ReconciledAt != nil {
  1913→				reconciledAtStr = app.Status.ReconciledAt.String()
  1914→			}
  1915→			reason = fmt.Sprintf("comparison expired, requesting refresh. reconciledAt: %v, expiry: %v", reconciledAtStr, statusRefreshTimeout)
  1916→			if hardExpired {
  1917→				reason = fmt.Sprintf("comparison expired, requesting hard refresh. reconciledAt: %v, expiry: %v", reconciledAtStr, statusHardRefreshTimeout)
  1918→				refreshType = appv1.RefreshTypeHard
  1919→			}
  1920→		} else if !app.Spec.Destination.Equals(app.Status.Sync.ComparedTo.Destination) {
  1921→			reason = "spec.destination differs"
  1922→		} else if app.HasChangedManagedNamespaceMetadata() {
  1923→			reason = "spec.syncPolicy.managedNamespaceMetadata differs"
  1924→		} else if !app.Spec.IgnoreDifferences.Equals(app.Status.Sync.ComparedTo.IgnoreDifferences) {
  1925→			reason = "spec.ignoreDifferences differs"
  1926→		} else if requested, level := ctrl.isRefreshRequested(app.QualifiedName()); requested {
  1927→			compareWith = level
  1928→			reason = "controller refresh requested"
  1929→		}
  1930→	}
  1931→
  1932→	if reason != "" {
  1933→		logCtx.Infof("Refreshing app status (%s), level (%d)", reason, compareWith)
  1934→		return true, refreshType, compareWith
  1935→	}
  1936→	return false, refreshType, compareWith
  1937→}
