  1939→func (ctrl *ApplicationController) refreshAppConditions(app *appv1.Application) (*appv1.AppProject, bool) {
  1940→	errorConditions := make([]appv1.ApplicationCondition, 0)
  1941→	proj, err := ctrl.getAppProj(app)
  1942→	if err != nil {
  1943→		errorConditions = append(errorConditions, ctrl.projectErrorToCondition(err, app))
  1944→	} else {
  1945→		specConditions, err := argo.ValidatePermissions(context.Background(), &app.Spec, proj, ctrl.db)
  1946→		if err != nil {
  1947→			errorConditions = append(errorConditions, appv1.ApplicationCondition{
  1948→				Type:    appv1.ApplicationConditionUnknownError,
  1949→				Message: err.Error(),
  1950→			})
  1951→		} else {
  1952→			errorConditions = append(errorConditions, specConditions...)
  1953→		}
  1954→	}
  1955→	app.Status.SetConditions(errorConditions, map[appv1.ApplicationConditionType]bool{
  1956→		appv1.ApplicationConditionInvalidSpecError: true,
  1957→		appv1.ApplicationConditionUnknownError:     true,
  1958→	})
  1959→	return proj, len(errorConditions) > 0
  1960→}
