  1962→// normalizeApplication normalizes an application.spec and additionally persists updates if it changed
  1963→func (ctrl *ApplicationController) normalizeApplication(orig, app *appv1.Application) {
  1964→	app.Spec = *argo.NormalizeApplicationSpec(&app.Spec)
  1965→	logCtx := getAppLog(app)
  1966→
  1967→	patch, modified, err := diff.CreateTwoWayMergePatch(orig, app, appv1.Application{})
  1968→
  1969→	if err != nil {
