   340→func diffArrayCached(configArray []*unstructured.Unstructured, liveArray []*unstructured.Unstructured, cachedDiff []*v1alpha1.ResourceDiff, opts ...diff.Option) (*diff.DiffResultList, error) {
   341→	numItems := len(configArray)
   342→	if len(liveArray) != numItems {
   343→		return nil, fmt.Errorf("left and right arrays have mismatched lengths")
   344→	}
   345→
   346→	diffByKey := map[kube.ResourceKey]*v1alpha1.ResourceDiff{}
   347→	for _, res := range cachedDiff {
   348→		diffByKey[kube.NewResourceKey(res.Group, res.Kind, res.Namespace, res.Name)] = res
   349→	}
   350→
   351→	diffResultList := diff.DiffResultList{
   352→		Diffs: make([]diff.DiffResult, numItems),
   353→	}
   354→
   355→	for i := 0; i < numItems; i++ {
   356→		config := configArray[i]
   357→		live := liveArray[i]
   358→		resourceVersion := ""
   359→		var key kube.ResourceKey
   360→		if live != nil {
   361→			key = kube.GetResourceKey(live)
   362→			resourceVersion = live.GetResourceVersion()
   363→		} else {
   364→			key = kube.GetResourceKey(config)
   365→		}
   366→		var dr *diff.DiffResult
   367→		if cachedDiff, ok := diffByKey[key]; ok && cachedDiff.ResourceVersion == resourceVersion {
   368→			dr = &diff.DiffResult{
   369→				NormalizedLive: []byte(cachedDiff.NormalizedLiveState),
   370→				PredictedLive:  []byte(cachedDiff.PredictedLiveState),
   371→				Modified:       cachedDiff.Modified,
   372→			}
   373→		} else {
   374→			res, err := diff.Diff(configArray[i], liveArray[i], opts...)
   375→			if err != nil {
   376→				return nil, err
   377→			}
   378→			dr = res
   379→		}
   380→		if dr != nil {
   381→			diffResultList.Diffs[i] = *dr
   382→			if dr.Modified {
   383→				diffResultList.Modified = true
   384→			}
   385→		}
   386→	}
   387→
   388→	return &diffResultList, nil
   389→}
